                WriteLiteral(@"
    <script>
        function togglePass(fieldId, iconId) {
            var field = document.getElementById(fieldId);
            var icon  = document.getElementById(iconId);
            if (field.type === 'password') {
                field.type = 'text';
                icon.classList.replace(
                    'mdi-eye-outline',
                    'mdi-eye-off-outline');
            } else {
                field.type = 'password';
                icon.classList.replace(
                    'mdi-eye-off-outline',
                    'mdi-eye-outline');
            }
        }
    </script>
");
            }
            );
